module RefModule(
    input clk,
    input reset,
    output reg [3:0] gray
    );

    reg [3:0] unused_count;

    always @(posedge clk) begin
        if (reset) begin
            unused_count <= 4'b0000;
        end else begin
            unused_count <= unused_count + 1;
        end
    end

    always @(unused_count) begin
        gray = (unused_count >> 1) ^ unused_count;
    end
endmodule
